"""
MKT Christ Commentary — Psalms chapters 105–106
Run: python3 scripts/zc-christ-psalms-105-106.py

Source data used:
- data/interlinear/psalms.json
- data/translation/draft/mediating/psalms.json (MKT text)
- data/commentary/mkt-christ/psalms.json (continuity)

Key Christological decisions in this range:
- Ps 105 is the positive "historical psalm" — God's faithfulness from Abraham through
  the Exodus. The Christological thread: Abraham covenant → Gal 3:16 (fulfilled in Christ);
  Joseph typology (sold, imprisoned, exalted to save) = NT's most explicit OT Christ-type;
  Moses and Aaron as types; Exodus provisions = New Exodus (cloud/fire = divine presence/
  John 1:14; quail/manna = bread of life / John 6; rock = 1 Cor 10:4 "the rock was Christ").
- Ps 106 is the dark counterpart — Israel's rebellion despite God's mighty acts. The thread:
  universal sin (Rom 3:23); Moses's intercession as type of Christ (1 Tim 2:5; Heb 7:25);
  "reckoned as righteousness" language (v.31 = imputation vocabulary of Rom 4-5);
  propitiation (wrath Christ absorbs, Rom 3:25); eschatological ingathering (John 11:52).
- Joseph typology: sold as a slave → Christ sold for silver (Matt 26:15); imprisoned/humiliated
  → passion; exalted to rule and save → resurrection/session. Acts 7:9-10 treats Joseph as
  a direct type without calling it that; the NT assumes the reader will recognize the pattern.
- Ps 106:23 Moses "stood in the gap" is the OT's clearest intercessor-mediator image; it
  prefigures Christ's permanent intercession more directly than any other single verse.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

PSALMS = {
  "105": {
    "1": '<p>A theme: the missional call — "make his deeds known among the nations" — is the OT anticipation of the Great Commission (Matt 28:19-20; Acts 1:8). What the psalm calls Israel to do for YHWH, the NT says Christ accomplishes through his followers. The nations are the audience not of religious information but of the proclaimed deeds of God in history, now centered on the Christ-event.</p>',
    "2": '<p>A theme: the praise of God expressed in singing is taken up in Christ, who leads his brothers in worship. Heb 2:12 applies Ps 22:22 to Christ: "I will declare your name to my brothers; in the midst of the assembly I will sing your praise." The song that the psalm calls Israel to sing is the song Christ himself sings as the firstborn among many brothers (Rom 8:29).</p>',
    "3": '<p>A theme: "boast in his holy name" — Phil 2:9-11 names the name above every name as the name of Jesus; Gal 6:14 says "may I never boast except in the cross of our Lord Jesus Christ." The holy name in which Israel boasts is ultimately the name of the Son, who perfectly bears and expresses the character of the Father (John 1:18; 17:6).</p>',
    "4": '<p>A theme: "seek the LORD and his power; seek his presence at all times" — in Christ this seeking is answered definitively. John 14:6 ("I am the way and the truth and the life; no one comes to the Father except through me") and John 1:18 present Christ as the presence and power of God made accessible. To seek God\'s face is now to encounter the face of Christ (2 Cor 4:6).</p>',
    "5": '<p>A revelation of God: YHWH is the God who performs signs, wonders, and judgments — his character disclosed through mighty acts. Jesus\'s signs in John\'s Gospel stand in this tradition: John 6:14 identifies him as "the Prophet who is to come" after the feeding miracle; the signs reveal that the God of the Exodus is present and acting in Christ. "Wonderful deeds" (<em>niplāʾôt</em>) frames the signs as theological disclosure, not merely miracle.</p>',
    "6": '<p>A theme: "children of Abraham, his servant" — Gal 3:29 redefines this identity in Christ: "if you belong to Christ, then you are Abraham\'s offspring, heirs according to the promise." The covenant lineage is not cancelled but fulfilled — the "children of Abraham" now includes all who share Abraham\'s faith, united in Christ the true seed (Gal 3:16: "the promises were spoken to Abraham and to his seed... meaning one person, who is Christ").</p>',
    "7": '<p>A revelation of God: YHWH is universal judge — "his judgments are in all the earth." The NT presents Christ as the appointed agent of this universal judgment: "the Father judges no one, but has entrusted all judgment to the Son" (John 5:22); "he has set a day when he will judge the world with justice by the man he has appointed" (Acts 17:31). Universal sovereignty is already implicit in the psalm and made explicit in Christ.</p>',
    "8": '<p>A direct connection: "he keeps his covenant in memory forever" — Luke 1:54-55 and 1:72-73 say God "remembered his covenant" in the Incarnation. The canticles of Luke deliberately invoke this theological tradition: YHWH\'s covenant memory, kept "forever," is activated in Christ. The new covenant (Luke 22:20 — "this cup is the new covenant in my blood") is the ultimate expression of covenant-memory fulfilled in blood.</p>',
    "9": '<p>A type: "the covenant he confirmed to Abraham, and his sworn promise to Isaac" — Paul calls this the proto-Gospel in Gal 3:8 ("the Scripture foresaw that God would justify the Gentiles by faith and announced the gospel in advance to Abraham"). Gal 3:15-17 argues that Christ is the mediator of this covenant; what was made with Abraham was always pointing to Christ as the singular heir through whom the blessing flows to all nations.</p>',
    "10": '<p>A theme: "he confirmed it to Jacob as a decree, to Israel as an everlasting statute" — Christ\'s statement "I have not come to abolish the Law but to fulfill it" (Matt 5:17) answers this everlasting statute. The covenant established with the patriarchs is not voided but brought to its intended goal (<em>telos</em>) in Christ (Rom 10:4). The statute is everlasting because the one who fulfills it is eternal.</p>',
    "11": '<p>A shadow: "to you I will give the land of Canaan as your inheritance" — the land promise is the first layer of a theological theme that expands in the NT. Heb 11:16 says the patriarchs were looking for "a better country — a heavenly one"; Matt 5:5 reinterprets "the meek shall inherit the land" as inheriting the earth; Rev 21:1-4 presents the renewed creation as the fulfillment. What Israel received as a down payment in Canaan, the redeemed receive in full through the Heir of all things (Heb 1:2).</p>',
    "12": '<p>A revelation of God: God works through the small and vulnerable to accomplish his purposes. The incarnation of Christ into a marginal people under Roman occupation, born in a stable with no room at the inn (Luke 2:7), continues the pattern. Divine election runs counter to human expectations of power and size: "God chose the weak things of the world to shame the strong" (1 Cor 1:27).</p>',
    "13": '<p>A revelation of God: "they wandered from nation to nation, from one kingdom to another people" — the patriarchal sojourn as the condition of covenant belonging. Heb 11:13-16 calls them "strangers and exiles on the earth." Christ himself was a refugee in Egypt (Matt 2:13-15) and had "nowhere to lay his head" (Luke 9:58), sharing the sojourner-condition of the covenant people and validating it as the shape of life under the cross.</p>',
    "14": '<p>A revelation of God: "he allowed no one to oppress them; he rebuked kings on their behalf" — divine protection of the covenant line through which Christ would come. The same providential protection guards the line of promise from the patriarchs to the flight into Egypt (Matt 2:13-15). God guards the line of promise because that line ultimately produces the Messiah.</p>',
    "15": '<p>A direct connection: "do not touch my anointed ones; do not harm my prophets" — <em>meshîḥîm</em> (anointed ones) is the plural of <em>meshîḥ</em> (Messiah/Christ). The term here protects the patriarchs but points forward to the Anointed One par excellence. The protected prophets form the chain of testimony culminating in Christ — who alone is ultimately "harmed" precisely so that harm falls on no one else.</p>',
    "16": '<p>A type: "when he called down famine over the land" — divine sovereign ordering of events to bring Joseph to prominence in Egypt. This launches the Joseph narrative, the most extended OT type of Christ. The famine that creates the crisis God uses to exalt his chosen servant anticipates the circumstances through which Christ\'s path to glory runs: through the cross to the crown (Phil 2:8-9).</p>',
    "17": '<p>A type: "he sent a man ahead of them — Joseph, sold as a slave" — Acts 7:9 treats Joseph as a direct antecedent of Jesus, both handed over by those who should have received them. Sold for twenty pieces of silver by his brothers (Gen 37:28) / Jesus sold for thirty by his disciple (Matt 26:15; cf. Zech 11:12-13). The "sending ahead" — prior to the salvation he would accomplish — types Christ sent as the forerunner who prepares the way (John 14:2-3; Heb 6:20).</p>',
    "18": '<p>A type: "they bruised his feet with shackles, his neck was put in an iron collar" — Joseph\'s imprisonment and physical suffering precede his exaltation. Phil 2:8 follows the same pattern: "he humbled himself and became obedient to death." The iron collar anticipates the crown of thorns; the shackles anticipate the nails. Humiliation preceding exaltation is the irreducible pattern of both Joseph and Christ.</p>',
    "19": '<p>A type: "this lasted until what he had foretold came true — all the while the word of the LORD was testing him" — the divine word that predicted Joseph\'s dreams tested him by delaying fulfillment. In Christ, "when the fullness of time had come" (Gal 4:4) — God acted according to a precise divine timetable. Christ\'s suffering was the test the word of God worked through before the promise was fulfilled (Heb 5:8: "he learned obedience from what he suffered").</p>',
    "20": '<p>A type: "the king sent word and freed him; the ruler of the peoples set him at liberty" — Joseph\'s release from imprisonment to royal authority is one of the OT\'s most direct resurrection types. Acts 2:24 uses the same logic for Christ: "God raised him from the dead, freeing him from the agony of death, because it was impossible for death to keep its hold on him." The imprisoned servant released by divine intervention to rule is the pattern both embody.</p>',
    "21": '<p>A type: "he made him master of his household, ruler of all he possessed" — Joseph\'s exaltation to Pharaoh\'s right hand (Gen 41:40-43) types Christ\'s session at the Father\'s right hand. Ps 110:1 ("sit at my right hand until I make your enemies a footstool") is the explicit messianic application; Eph 1:20-22 applies this to Christ: God "seated him at his right hand... and placed all things under his feet." The Joseph-figure exalted to the ruler\'s side is the OT\'s structural preview.</p>',
    "22": '<p>A type: "to instruct his princes at his pleasure and teach his elders wisdom" — Joseph\'s authority to instruct the powerful in Egypt anticipates Christ\'s authority as teacher. Matt 7:29 says Jesus taught "as one who had authority, not as their teachers of the law"; 1 Cor 1:30 calls Christ "our wisdom from God." The exalted servant who teaches the powerful shadows the exalted Christ who is wisdom incarnate.</p>',
    "23": '<p>A type: "Israel entered Egypt, Jacob sojourned in Ham\'s territory" — Matt 2:14-15 cites this pattern directly, applying Hos 11:1 ("out of Egypt I called my son") to Jesus\'s sojourn in Egypt. The evangelist reads the Exodus typologically: Israel-in-Egypt types Christ-in-Egypt; the calling "out of Egypt" fulfilled first in the Exodus is the pattern re-enacted in Christ\'s return. The descent into Egypt is a type of the incarnation — the Son entering foreign territory before being called home.</p>',
    "24": '<p>A revelation of God: "the LORD made his people very fruitful" — multiplication of the covenant people despite opposition is YHWH\'s pattern. John 15:5 ("those who remain in me... will bear much fruit") applies the growth-pattern to Christ and his people. The fruitfulness of Israel in Egypt types the fruitfulness of the Church in an opposed world, both dependent on divine blessing, not human strategy.</p>',
    "25": '<p>A revelation of God: "he turned their hearts to hate his people" — divine sovereignty ordering even the hostility of Pharaoh. Acts 4:27-28 uses the same logic for the crucifixion: Herod and Pilate, Gentiles and Israel "did what your power and will had decided beforehand should happen." Even Christ\'s enemies serve the purposes of the one who "turned their hearts," making the cross the supreme example of God\'s sovereignty over hostile human will.</p>',
    "26": '<p>A type: "he sent Moses his servant, and Aaron whom he had chosen" — Moses the servant-deliverer prefigures Christ in Deut 18:15 ("a prophet like me"), applied to Jesus in Acts 3:22. Aaron prefigures the high priest: Heb 5:4 says Aaron was called by God, not self-appointed; Christ likewise (Heb 5:5-6). Both prophet and high priest are united in Christ, who is simultaneously the prophet who speaks God\'s word and the priest who mediates through sacrifice.</p>',
    "27": '<p>A type: "they performed his signs among them, worked wonders in Egypt" — the signs of Moses and Aaron type Jesus\'s signs. John 6:14 after the feeding miracle: "Surely this is the Prophet who is to come" — the crowd reads the sign against the background of Moses\'s wonder-working. Where the Mosaic signs pointed to Sinai, the Johannine signs point to the cross and resurrection as the definitive act of divine self-disclosure.</p>',
    "28": '<p>A shadow: "he sent darkness and made the land dark" — the ninth plague (Exod 10:21-23) anticipates the darkness at the crucifixion (Matt 27:45: "from the sixth hour to the ninth hour darkness came over all the land"). Both are signs of divine judgment; the darkness at Calvary signals that Christ is absorbing the judgment that the Egyptian plagues historically embodied — the plague falls on the Deliverer, not his people.</p>',
    "29": '<p>A shadow: the plagues are instruments of covenant judgment. Gal 3:13 ("Christ redeemed us from the curse of the law by becoming a curse for us") is the NT logic: the curse-judgments that fell on Egypt in the Exodus are previews of the judgment Christ absorbs at Calvary. His people are delivered through his blood — as Israel was, through the Passover blood on the doorposts — not by the blood of their enemies.</p>',
    "30": '<p>A shadow: "their land swarmed with frogs, even in the chambers of their kings" — the plague that invaded the centers of worldly power. In Christ the Gospel itself penetrates "even in Caesar\'s household" (Phil 4:22). The divine advance against human power-structures previewed in the Exodus plagues continues in the spread of Christ\'s kingdom — no human power, however entrenched, is beyond the reach of God\'s intervention.</p>',
    "31": '<p>A revelation of God: "he spoke and there came swarms of flies, gnats throughout their territory" — God accomplishes judgment through his word alone. "He spoke and it came to be" (Ps 33:9). Christ is the Word through whom all things were made and through whom all divine purposes are accomplished (John 1:3; Heb 1:3 — "sustaining all things by his powerful word").</p>',
    "32": '<p>A shadow: "he gave them hail for rain, lightning through their land" — storm as divine judgment. The seventh plague (Exod 9:23-26) becomes eschatological judgment imagery in Rev 8:7; 11:19; 16:21. Christ\'s stilling of the storm (Mark 4:39) shows his authority over the elements that bring judgment — he is master of the powers that embody divine wrath, pointing to his authority to face judgment at Calvary and emerge victorious.</p>',
    "33": '<p>A shadow: "he struck their vines and fig trees, shattered the trees" — the fig tree is a prophetic symbol for Israel (Jer 8:13; Hos 9:10; Joel 1:7). Christ\'s cursing of the barren fig tree (Mark 11:12-14, 20-21) is a prophetic sign-act echoing the plague-judgments: unfruitful religious structures under divine judgment. The destroyed trees of the plague become the withered fig tree of the Passion week.</p>',
    "34": '<p>A shadow: "he spoke and the locusts came, grasshoppers without number" — the locust plague (Exod 10:4-19) is the background for Rev 9:3 and the eschatological locust-judgment of Joel 1-2. Christ who averts the plague for those under his blood (1 Cor 5:7 — "our Passover lamb") brings the full harvest-judgment on those who are not. The plague-averted becomes the eschatological judgment only the Lamb can prevent.</p>',
    "35": '<p>A shadow: "they consumed every plant in their land" — total destruction as covenantal judgment. Heb 12:29 ("our God is a consuming fire") stands in this tradition. Christ who is the vine (John 15:1) warns that fruitless branches are "thrown into the fire and burned" (John 15:6). The consuming judgment of the Exodus plagues reaches its final form in Christ\'s eschatological judgment at the harvest.</p>',
    "36": '<p>A type: "he struck down every firstborn in their land" — the Passover judgment. 1 Cor 5:7 makes the typological link explicit: "Christ, our Passover lamb, has been sacrificed." The death of Egypt\'s firstborn is averted for Israel by the lamb\'s blood; the final judgment is averted for all under the blood of Christ, who is himself "the firstborn from the dead" (Col 1:18; Rev 1:5) — the firstborn who died so that God\'s firstborn-people might live.</p>',
    "37": '<p>A type: "he brought his people out loaded with silver and gold; not one person in all their tribes was weak" — the Exodus plunder and the strength of the redeemed. Col 2:15 applies plunder-language to the cross: Christ "disarmed the powers and authorities, making a public spectacle of them, triumphing over them." The Exodus plunder of Egypt types Christ\'s despoiling of the enemy at Calvary; the redeemed people leave strong because their deliverer has prevailed.</p>',
    "38": '<p>A revelation of God: "Egypt was glad when they left, for dread of them had fallen on them" — reversal of the oppressor-and-oppressed dynamic. In Christ\'s resurrection the ultimate reversal occurs: the powers that crucified him are defeated. Acts 2:36 ("God has made this Jesus both Lord and Christ") declares that the executed one is now the feared one — the full reversal the Exodus only previewed.</p>',
    "39": '<p>A type: "he spread out a cloud as a shelter and gave fire to light the way through the night" — the pillar of cloud and fire is the Shekinah, the localized divine presence with Israel. John 1:14 ("the Word became flesh and <em>tabernacled</em> among us — and we have seen his glory") is the explicit fulfillment. Christ is the cloud and fire — the divine presence made incarnate; John 8:12 ("I am the light of the world") applies the fire-pillar image directly to himself.</p>',
    "40": '<p>A type: "they asked for food and he brought them quail, satisfying them with bread from heaven" — this text stands directly behind Jesus\'s feeding miracles and John 6\'s bread-of-life discourse. John 6:31-35 quotes the manna tradition and Jesus responds: "my Father gives you the true bread from heaven... I am the bread of life." The manna gave temporary physical life; Christ gives life that endures forever (John 6:51). The type is fulfilled in the one who is himself the bread.</p>',
    "41": '<p>A type: "he split open the rock and water poured out" — 1 Cor 10:4 states the typological connection explicitly: "they drank from the spiritual rock that accompanied them, and that rock was Christ." The water from the rock (Exod 17:6; Num 20:11) is the NT\'s most directly named Christ-type. John 7:37-38 applies the same imagery to the Spirit poured out through Christ: "rivers of living water will flow from within them" — water from the rock becomes the Spirit from the crucified side (John 19:34).</p>',
    "42": '<p>A direct connection: "for he had called to mind his holy promise to Abraham his servant" — Luke 1:72-73 says God "remembered his holy covenant, the oath he swore to our father Abraham." The Exodus is the first fulfillment of the Abrahamic promise; the Incarnation is the ultimate fulfillment. In Christ, God permanently "remembers" Abraham — the promise is not merely kept but fully redeemed in the one who is Abraham\'s seed (Gal 3:16).</p>',
    "43": '<p>A type: "he led his people out with rejoicing, his chosen ones with shouts of joy" — the New Exodus motif of Isa 51:11; 55:12 is fulfilled in Christ. 1 Pet 1:8 describes the joy of those redeemed by Christ: "you believe in him and are filled with an inexpressible and glorious joy." The joyful departure from bondage types the eschatological rejoicing of the redeemed, who "come to Mount Zion" with "everlasting joy upon their heads" (Isa 35:10).</p>',
    "44": '<p>A shadow: "he gave them the lands of other nations, and they took possession of what others had worked for" — Israel\'s inheritance of Canaan types the inheritance of believers in Christ. Rom 8:17 ("co-heirs with Christ"); Heb 1:2 ("appointed heir of all things"); Rev 21:7 ("the one who is victorious will inherit all this") — the land-gift expands to cosmic scope. What Israel received as a down payment in Canaan, the redeemed receive in full through the Heir of all things.</p>',
    "45": '<p>A revelation of God: "so that they would keep his decrees and obey his teachings — Praise the LORD!" — the Exodus\'s stated purpose: covenant-obedience. This goal is fulfilled in Christ through the new covenant: "I will put my law in their minds and write it on their hearts" (Jer 31:33; Heb 8:10-11). What the Exodus could not achieve by law alone — willing, inward obedience — the Spirit of Christ accomplishes (Ezek 36:26-27; Rom 8:4). The psalm\'s closing praise is the response to grace-enabled obedience becoming finally possible.</p>',
  },
  "106": {
    "1": '<p>A revelation of God: "for he is good; his steadfast love endures forever" — the foundational covenant-affirmation. In Eph 2:4-7, Paul\'s account of salvation begins with precisely this: "But God, who is rich in mercy, because of his great love for us..." The <em>hesed</em> praised in this doxology is the very attribute expressed definitively in Christ\'s self-giving. The goodness of God toward the undeserving is the theme of both Psalm 106 and the Gospel.</p>',
    "2": '<p>A theme: "who is able to speak all the LORD\'s mighty deeds?" — the question implies the answer is no mere human. John 1:18 provides it: "No one has ever seen God, but the one and only Son, who is himself God and is in closest relationship with the Father, has made him known." Christ is the one who definitively declares the Father\'s mighty deeds because he both performs them and is himself their content (John 5:19-20).</p>',
    "3": '<p>A theme: "blessed are those who uphold justice and do what is right at every moment" — Matt 5:6 echoes this beatitude form: "blessed are those who hunger and thirst for righteousness, for they will be satisfied." Christ both perfectly embodies this blessing (Matt 3:15: "fulfill all righteousness") and gives it as a gift: 1 Cor 1:30 says Christ "has become for us... our righteousness." The one who blesses is the one who fulfills what the blessing requires.</p>',
    "4": '<p>A direct connection: "remember me, O LORD, when you show favor to your people" — the same plea appears on the dying thief\'s lips: "Jesus, remember me when you come into your kingdom" (Luke 23:42). Christ\'s response — "today you will be with me in paradise" — is the divine answer. He is the one through whom YHWH "shows favor"; the petitioner who prays to be remembered is answered in Christ who carries the petitioner into his own kingdom and life.</p>',
    "5": '<p>A theme: "so that I may see the well-being of your chosen ones, share the joy of your nation" — the petition to be included among the covenant people. Eph 1:4-5 says believers were "chosen in Christ before the foundation of the world" and "predestined for adoption as sons through Jesus Christ." The identity that was Israel\'s by birth becomes available to all through union with Christ — "the Chosen One" (Luke 23:35) who includes others in his election.</p>',
    "6": '<p>A direct connection: "we have sinned, just as our fathers did" — universal sin across generations. Rom 3:23 ("all have sinned and fall short of the glory of God") and Rom 5:12 expand this generational confession to all humanity. Christ is the one who takes on the full weight of this accumulated sin: "God made him who had no sin to be sin for us, so that in him we might become the righteousness of God" (2 Cor 5:21). The psalm\'s confession is precisely what Christ bears.</p>',
    "7": '<p>A revelation of God: "they did not remember your abundant steadfast love" — the failure of memory that leads to covenant failure. Jesus institutes the Eucharist as the direct remedy: "do this in remembrance of me" (1 Cor 11:24-25). The Last Supper creates a perpetual memory-practice for the covenant community — the answer to Israel\'s forgetfulness is a covenant meal designed to keep Christ\'s saving act in perpetual, enacted memory.</p>',
    "8": '<p>A direct connection: "but he saved them for the sake of his own name, to demonstrate his mighty power" — God\'s salvation is for the honor of his name. John 17:6 ("I have revealed your name") and 12:28 ("Father, glorify your name!") show Christ understanding his mission in these terms. Rom 3:25-26 argues that God presented Christ as a propitiation "to demonstrate his righteousness." Salvation accomplishes both rescue and divine self-vindication.</p>',
    "9": '<p>A type: "he rebuked the Red Sea and it dried up; he led them through the depths as through a desert" — 1 Cor 10:1-2 interprets the sea-crossing as a baptismal type: "they were all baptized into Moses in the cloud and in the sea." Baptism into Christ (Rom 6:3-4) is the fulfillment: passing through death-waters to new life. The Red Sea is the precursor of the cross — the people pass through the waters of judgment because the road has been opened by divine power over chaos.</p>',
    "10": '<p>A type: "he saved them from the hand of the one who hated them and redeemed them from the power of the enemy" — the Exodus as redemption from enemy power. Col 1:13 uses the same language: "he has rescued us from the dominion of darkness." Heb 2:14-15 says Christ shared in flesh and blood "so that by his death he might break the power of him who holds the power of death — that is, the devil." The enemy is personalized and the rescue is through death itself.</p>',
    "11": '<p>A shadow: "the waters covered their enemies; not one of them remained" — the destruction of Pharaoh\'s army. Rev 19:11-21 draws on Exodus imagery for the final destruction of the beast and his armies. The eschatological "sea giving up its dead" (Rev 20:13) and the beast cast into the lake of fire complete the trajectory of this divine military victory. Christ as the cosmic warrior of Rev 19:11-16 is the fulfillment of this total divine victory.</p>',
    "12": '<p>A theme: "then they believed his words and sang his praise" — faith responding to salvation in song. This is the pattern of Gospel response. The Song of Moses (Exod 15) is the template for Revelation\'s "song of Moses and of the Lamb" (Rev 15:3-4) — the redeemed singing their salvation. Faith, praise, and song are the response of those saved by Christ, replicating the pattern established at the sea.</p>',
    "13": '<p>A revelation of God: "but soon they forgot what he had done and did not wait for his counsel" — forgetting as the root of covenant failure. The Eucharist is Christ\'s direct response to this pattern: "do this in remembrance of me" (1 Cor 11:24-25). The Last Supper creates a perpetual memory-practice for the covenant community — directly addressing the forgetfulness the psalm laments. Covenant memory is constitutive of covenant faithfulness.</p>',
    "14": '<p>A type: "they craved intensely in the wilderness and put God to the test in the desert" — the wilderness testing of Israel is what Jesus retraced and reversed. Matt 4:1-11 places Jesus in the wilderness where he is tested at precisely the points where Israel failed: bread, testing God, idolatry. Heb 4:15 confirms: "we have a high priest... tempted in every way, just as we are — yet was without sin." Israel failed the wilderness test; Christ passed it, accomplishing what Israel could not.</p>',
    "15": '<p>A revelation of God: "he gave them what they asked for but sent a wasting disease into their lives" — the tragic dynamic of getting what you demand apart from God\'s true provision. John 6:32-35 contrasts the craved manna with Christ himself: "my Father gives you the true bread from heaven... I am the bread of life; whoever comes to me will never go hungry." The craving for inferior provision contrasts with the satisfaction Christ provides — the one who alone truly satisfies.</p>',
    "16": '<p>A shadow: "in the camp they were envious of Moses, Aaron the holy one of the LORD" — envy directed at God\'s appointed leaders. Matt 27:18 identifies envy as the motive behind Christ\'s crucifixion: "he knew it was out of envy that they had handed Jesus over." The envious rejection of God\'s chosen mediators is the persistent human pattern; in Christ this pattern reaches its ultimate and most paradoxically redemptive expression — the envied one crucified becomes the source of life for those who crucified him.</p>',
    "17": '<p>A revelation of God: "the earth opened and swallowed up Dathan, the group of Abiram closed over them" — divine judgment on those who rebel against YHWH\'s appointed mediators. Heb 10:29 warns against treating lightly "the blood of the covenant" and "insulting the Spirit of grace" — the judgment for rejecting Christ, the ultimate mediator, is more severe than the Korah-judgment. The pattern of judgment on mediator-rejecters is not cancelled in the NT but intensified.</p>',
    "18": '<p>A revelation of God: "fire broke out in their company, the flame consumed the wicked" — divine fire consuming covenant rebels. Heb 12:29 applies this: "our God is a consuming fire." The same fire that consumed Korah\'s company is the eschatological fire Christ speaks of (Matt 25:41). Those in Christ are not consumed because he has borne the fire at Calvary (Isa 43:2: "when you walk through fire, you will not be burned... for I am the LORD your God").</p>',
    "19": '<p>A type: "at Horeb they made a calf and bowed down to a metal idol" — the golden calf as paradigmatic idolatry. 1 Cor 10:7 applies this: "do not be idolaters, as some of them were." Positively, Christ is "the image of the invisible God" (Col 1:15) — the true "form" of God that Israel sought to manufacture. What Israel tried to create in gold was the divine image already present in the Son; the idol replaces the image that was always waiting to be revealed in the Incarnation.</p>',
    "20": '<p>A direct connection: "they traded the glory of God for the image of a grass-eating ox" — Rom 1:23 quotes this language to describe universal human idolatry: "they exchanged the glory of the immortal God for images." This exchange is the root of all human corruption (Rom 1:18-25). Christ is "the image of the invisible God" (Col 1:15; 2 Cor 4:4) — the one in whom the glory that humans have traded away is restored and made visible. Beholding Christ reverses the idolatrous exchange.</p>',
    "21": '<p>A revelation of God: "they forgot God their Savior" — YHWH as <em>mōšîaʿ</em> (Savior) forgotten by his own people. Matt 1:21 names Jesus (<em>Yēšûaʿ</em> = YHWH saves) as the Savior who comes to his people; Luke 2:11 ("a Savior has been born to you"). The people who forgot the Exodus-Savior now encounter him incarnate — the name Jesus itself carries the Exodus-rescue tradition forward, declaring in every use that YHWH has come to save.</p>',
    "22": '<p>A revelation of God: "wonderful things in the land of Ham and awesome deeds by the Red Sea" — recitation of historical mighty acts. The Christological weight is cumulative: every act of divine rescue and power in the Exodus is a type pointing to the definitive rescue. Heb 9:11-12 presents Christ\'s work as achieving what the entire Exodus-and-Tabernacle pattern could only preview: "eternal redemption" accomplished "once for all" by his own blood.</p>',
    "23": '<p>A direct connection: "Moses, his chosen one, stood in the gap before him and turned his anger away from destroying them" — the OT\'s most concentrated image of intercessory mediation. The NT applies the gap-standing to Christ with extraordinary clarity: 1 Tim 2:5 ("one mediator between God and mankind, the man Christ Jesus"); Heb 7:25 ("he always lives to intercede for them"); Ezek 22:30 lamented that no one could "stand in the gap" — the gap Christ fills permanently through his intercession, based not on prayer alone but on his own shed blood (Heb 9:24; 12:24).</p>',
    "24": '<p>A direct connection: "then they despised the pleasant land; they did not trust his word" — the Kadesh-barnea unbelief. Heb 3:7–4:11 applies this directly to faith in Christ: "since the promise of entering his rest still stands, let us be careful that none of you be found to have fallen short of it" (4:1). The rest Israel failed to enter through unbelief is available through Christ; he is himself the Sabbath-rest (Heb 4:9-10: "there remains a Sabbath-rest for the people of God").</p>',
    "25": '<p>A revelation of God: "they grumbled in their tents and did not listen to the LORD\'s voice" — grumbling as covenantal hardness. In contrast, John 8:29 ("I always do what pleases him") and Heb 10:7 (Christ: "I have come to do your will, my God") present Jesus as the obedient Son who never grumbles. Christ\'s perfect obedience is what Israel\'s grumbling failure required — one who listened and obeyed in the very place where Israel refused.</p>',
    "26": '<p>A direct connection: "so he swore with uplifted hand that he would make them fall in the wilderness" — the divine oath of exclusion from rest. Heb 4:3 cites this oath: "as I declared on oath in my anger, \'They shall never enter my rest.\'" The oath stands against unbelief. But the same God who swore this oath also swore regarding Christ: "you are a priest forever, in the order of Melchizedek" (Ps 110:4; Heb 7:21). The oath of exclusion is answered by the oath of priestly provision — Christ opens the rest that unbelief had closed.</p>',
    "27": '<p>A shadow: "and disperse their descendants among the nations, scattering them through the lands" — exile as covenant curse. John 11:52 says Christ died "to gather together the scattered children of God." Eph 2:11-22 describes the ingathering: Gentiles "far off" brought near "through the blood of Christ." The scattering of exile — the covenant curse — is reversed through the cross, which creates one new humanity from the scattered peoples.</p>',
    "28": '<p>A shadow: "they joined themselves to Baal-peor and ate sacrifices offered to the dead" — eating at the table of false gods. 1 Cor 10:20-21 applies this directly: "the sacrifices of pagans are offered to demons... you cannot have a part in both the Lord\'s table and the table of demons." The contrast between the Lord\'s Supper and the Baal-peor meals is explicit in Paul. Christ\'s table displaces every table of idols as the place of true communion — the living Christ against the sacrifices offered to the dead.</p>',
    "29": '<p>A shadow: "they aroused his anger with their practices, and plague broke out among them" — sin leading to divine judgment. Isa 53:4 says of the Servant: "surely he took up our pain and bore our suffering... yet we considered him punished by God, stricken by him, and afflicted." The word rendered "stricken" carries resonances of divine plague-striking. Christ bears the plague-judgment on Israel\'s behalf — the one on whom it finally fell so that it need not fall on his people (1 Cor 5:7: "our Passover lamb").</p>',
    "30": '<p>A shadow: "then Phinehas stepped forward and executed judgment, and the plague was stopped" — one decisive priestly action stopping consuming judgment. The pattern of a single person\'s action stopping divine wrath points toward Christ\'s atoning work, though Phinehas\'s means (violent execution) contrasts with Christ\'s (his own death). Heb 9:26 ("he appeared to do away with sin by the sacrifice of himself") is the fulfillment: the one who steps forward to end the plague does so by becoming the offering — the atonement accomplished from within rather than imposed from without.</p>',
    "31": '<p>A direct connection: "and it was reckoned to him as righteousness for all generations, forever" — the <em>ḥāšab lĕṣĕdāqâ</em> (reckoned/credited as righteousness) vocabulary. Rom 4:3 applies the same formula to Abraham; Rom 5:18-19 extends it: "through the one man\'s obedience many will be made righteous." The forensic reckoning-of-righteousness that appears here and in Gen 15:6 becomes the technical language of justification by faith in Christ (Rom 3:21-26; 4:24-25). The pattern of credited righteousness anticipates the imputed righteousness of Christ.</p>',
    "32": '<p>A shadow: "they angered him at the waters of Meribah, and it went badly for Moses because of them" — Moses excluded from Canaan due to the people\'s sin. Moses\'s exclusion because of the people\'s rebellion is a somber shadow of Christ bearing consequences for the people\'s failures. But the contrast is more illuminating: Moses was excluded from the promised land; Christ enters the final promised land as the forerunner (Heb 6:20), bringing his people with him where the greatest human mediator was barred.</p>',
    "33": '<p>A revelation of God: "for they rebelled against his Spirit" — rebellion against the Spirit of God is a persistent Israelite pattern. Acts 7:51 charges the Sanhedrin: "you always resist the Holy Spirit!" Matt 12:31-32 identifies blasphemy against the Holy Spirit as the unforgivable sin. The Spirit who was provoked at Meribah (Isa 63:10-11) is the same Spirit poured out at Pentecost (Acts 2) — Israel\'s historical rebellion against the Spirit is the backdrop for the NT\'s urgent warnings against grieving and resisting him.</p>',
    "34": '<p>A revelation of God: "they did not destroy the peoples the LORD had commanded them to" — incomplete obedience is the failure-pattern catalogued throughout the psalm. Matt 3:15 — "it is proper for us to do this to fulfill all righteousness" — presents Christ as the one who fulfills what Israel consistently failed to fulfill. Christ completes the divine mandate without remainder; his obedience is total where Israel\'s was always partial (Rom 5:19: "through the obedience of the one man many will be made righteous").</p>',
    "35": '<p>A theme: "they mingled with the nations and learned their ways" — syncretistic assimilation. Rom 12:2 addresses the same temptation: "do not conform to the pattern of this world, but be transformed by the renewing of your mind." In Christ the relationship to the nations is transformed: the goal is not separation from the nations but witness to them (Matt 28:19-20) — not assimilation but incarnational presence. Christ creates a community that is "in the world but not of the world" (John 17:14-16).</p>',
    "36": '<p>A theme: "they served their idols, which became a snare to them" — the enslaving power of idolatry. Gal 4:8-9 describes pre-Christ existence as "slavery to those who by nature are not gods." Christ frees from this slavery: "if the Son sets you free, you will be free indeed" (John 8:36). The snare of idolatry is broken by the one whose yoke is easy and whose burden is light (Matt 11:29-30) — the service that liberates rather than enslaves.</p>',
    "37": '<p>A shadow: "they sacrificed their sons and daughters to demons" — child sacrifice to Molech, the extreme consequence of idolatry. The contrast with Christ is starkest here: God does not demand the sacrifice of children; God himself provides the sacrifice — his own Son — so that no more blood need be shed. Gen 22:8 ("God himself will provide the lamb") and John 3:16 ("God so loved the world that he gave his one and only Son") answer the demonic sacrifice with the divine gift.</p>',
    "38": '<p>A shadow: "they shed innocent blood, the blood of their sons and daughters... and the land was polluted with blood" — innocent blood polluting the land. Matt 27:4 (Judas: "I have betrayed innocent blood") and 27:24-25 (Pilate washing his hands) frame Christ\'s death in these terms. But unlike the innocent blood that pollutes, Christ\'s blood cleanses: "the blood of Jesus, his Son, purifies us from all sin" (1 John 1:7; Heb 9:14). The pollution-through-blood becomes purification-through-blood — the ultimate reversal.</p>',
    "39": '<p>A theme: "they thus defiled themselves by their deeds and played the harlot with their practices" — covenant unfaithfulness as spiritual adultery. Eph 5:25-32 presents the marriage metaphor: Christ is the Husband who "loved the church and gave himself up for her to make her holy, cleansing her by the washing with water through the word." The faithless bride does not render the husband faithless; Christ loves and cleanses the unfaithful bride — the ultimate expression of the steadfast love the psalm\'s opening praised.</p>',
    "40": '<p>A direct connection: "then the LORD\'s anger blazed against his own people" — divine wrath against the covenant people. Rom 3:25 says God presented Christ as a "<em>hilastērion</em> (propitiation) through faith in his blood" — propitiation is the satisfaction of divine wrath. Christ absorbs the burning anger that centuries of covenant violation accumulated. 1 John 2:2 says Christ "is the propitiation for our sins, and not for ours only but also for the sins of the whole world." The blazing anger of Ps 106:40 is quenched in Christ.</p>',
    "41": '<p>A shadow: "he handed them over to the nations, and those who hated them ruled over them" — subjugation as covenant consequence. The ultimate reversal is Christ\'s kingdom: "the kingdom of the world has become the kingdom of our Lord and of his Messiah, and he will reign forever and ever" (Rev 11:15). Those who were "handed over" to hostile rulers now reign with Christ (Rev 5:10); those who mocked and ruled become subject to the one they condemned (Phil 2:10-11).</p>',
    "42": '<p>A shadow: "their enemies oppressed them and brought them under their power" — subjugation and powerlessness. 1 Cor 15:24-27 says Christ "must reign until he has put all his enemies under his feet... the last enemy to be destroyed is death." Every form of oppressive domination in the biblical narrative — Pharaoh, Babylon, Rome — anticipates the final enemy. Christ\'s resurrection is the decisive victory over all subjugating power, the beginning of the end of all oppression.</p>',
    "43": '<p>A type: "many times he delivered them, but they were rebellious... and sank low in their iniquity" — the judges-cycle of rebellion, oppression, cry, deliverance, repeated endlessly. Each act of deliverance types Christ\'s definitive deliverance. Christ breaks the cycle permanently: "Christ died to sin once for all" (Rom 6:10). The "many times" of the judges anticipates the "once for all" of Calvary (Heb 9:26-28; 10:10) — Christ does not repeat the cycle but ends it.</p>',
    "44": '<p>A revelation of God: "but he took note of their distress when he heard their cry" — the God who hears the cry of the distressed. This is the Exodus pattern (Exod 3:7). Christ enters into human distress as a participant: "we do not have a high priest who is unable to empathize with our weaknesses" (Heb 4:15). The God who hears becomes the God who suffers alongside — and the God who delivers from within the suffering rather than from above it.</p>',
    "45": '<p>A direct connection: "he remembered his covenant for their sake and relented according to his great steadfast love" — covenant-memory and <em>hesed</em> as the basis of every deliverance. Luke 22:20 ("this cup is the new covenant in my blood") is the ultimate covenant-remembrance: God does not merely recall the covenant but seals it with Christ\'s blood. The <em>hesed</em> that drove each judges-cycle deliverance is "expressed fully" (Titus 3:4-5) in Christ\'s self-giving on the cross.</p>',
    "46": '<p>A revelation of God: "he caused them to be pitied by all their captors" — God softening enemies\' hearts toward captives. Joseph in Egypt, Daniel in Babylon — God grants favor in enemy territory. Christ goes further: "Father, forgive them, for they do not know what they are doing" (Luke 23:34) — not just softening captors but praying for executioners. Divine compassion toward the captive reaches its furthest expression in the cross, where the captive prays for his captors.</p>',
    "47": '<p>A direct connection: "save us, O LORD our God, and bring us back from among the nations" — the petition for eschatological ingathering. John 11:52 says Christ died "to bring together the scattered children of God." Eph 2:11-22: Gentiles "far off" brought near "through the blood of Christ." The final praise the psalm anticipates — "giving thanks to your holy name" — is the worship of the redeemed from every nation: "a great multitude that no one could count, from every nation, tribe, people and language" (Rev 7:9-10).</p>',
    "48": '<p>A direct connection: "Blessed be the LORD, the God of Israel, from everlasting to everlasting! And let all the people say, \'Amen.\' Praise the LORD!" — the closing doxology of Book IV. Phil 2:10-11 is its fulfillment: "at the name of Jesus every knee should bow... and every tongue acknowledge that Jesus Christ is Lord, to the glory of God the Father." The universal "Amen" that the psalm calls for from "all the people" is the eschatological worship of the Lamb (Rev 5:13-14; 19:4) — the end to which all Scripture\'s praise-calls finally point.</p>',
  }
}

def main():
    existing = load_comm('mkt-christ', 'psalms')
    merge_comm(existing, PSALMS)
    save_comm('mkt-christ', 'psalms', existing)
    print('Psalms 105–106 mkt-christ written.')

if __name__ == '__main__':
    main()
